import pika
import json
import time
import sys
from datetime import datetime


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
    
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
    
    def publish_message(self, message):
        if not self.channel:
            self.connect()
        
        message_body = json.dumps(message)
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message_body,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"[x] Sent: {message}")
    
    def close(self):
        if self.connection:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
    
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
    
    def callback(self, ch, method, properties, body):
        message = json.loads(body)
        print(f"[x] Received: {message}")
        
        task_type = message.get('type', 'unknown')
        task_data = message.get('data', {})
        
        print(f"[*] Processing task: {task_type}")
        self.process_task(task_type, task_data)
        
        ch.basic_ack(delivery_tag=method.delivery_tag)
        print(f"[✓] Task completed: {task_type}")
    
    def process_task(self, task_type, task_data):
        if task_type == 'compute':
            time.sleep(task_data.get('duration', 1))
            print(f"    Computed result for: {task_data.get('value', 'N/A')}")
        elif task_type == 'email':
            time.sleep(1)
            print(f"    Sent email to: {task_data.get('recipient', 'N/A')}")
        elif task_type == 'report':
            time.sleep(2)
            print(f"    Generated report: {task_data.get('report_id', 'N/A')}")
        else:
            print(f"    Unknown task type: {task_type}")
    
    def start_consuming(self):
        if not self.channel:
            self.connect()
        
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        print(f'[*] Waiting for messages in queue: {self.queue_name}')
        print('[*] To exit press CTRL+C')
        self.channel.start_consuming()
    
    def close(self):
        if self.connection:
            self.connection.close()


def run_publisher():
    publisher = RabbitMQPublisher()
    publisher.connect()
    
    tasks = [
        {
            'type': 'compute',
            'data': {'value': 42, 'duration': 2},
            'timestamp': datetime.now().isoformat()
        },
        {
            'type': 'email',
            'data': {'recipient': 'user@example.com', 'subject': 'Task Notification'},
            'timestamp': datetime.now().isoformat()
        },
        {
            'type': 'report',
            'data': {'report_id': 'RPT-001', 'format': 'PDF'},
            'timestamp': datetime.now().isoformat()
        },
        {
            'type': 'compute',
            'data': {'value': 100, 'duration': 1},
            'timestamp': datetime.now().isoformat()
        },
        {
            'type': 'email',
            'data': {'recipient': 'admin@example.com', 'subject': 'System Alert'},
            'timestamp': datetime.now().isoformat()
        }
    ]
    
    for task in tasks:
        publisher.publish_message(task)
        time.sleep(0.5)
    
    publisher.close()
    print("\n[✓] All messages published successfully")


def run_consumer():
    consumer = RabbitMQConsumer()
    try:
        consumer.connect()
        consumer.start_consuming()
    except KeyboardInterrupt:
        print('\n[!] Interrupted')
        consumer.close()
        sys.exit(0)
    except Exception as e:
        print(f'[!] Error: {e}')
        consumer.close()
        sys.exit(1)


if __name__ == '__main__':
    if len(sys.argv) > 1:
        mode = sys.argv[1]
        if mode == 'publish':
            run_publisher()
        elif mode == 'consume':
            run_consumer()
        else:
            print("Usage: python script.py [publish|consume]")
    else:
        print("Select mode:")
        print("1. Publisher")
        print("2. Consumer")
        choice = input("Enter choice (1 or 2): ")
        
        if choice == '1':
            run_publisher()
        elif choice == '2':
            run_consumer()
        else:
            print("Invalid choice")